sql:
SELECT nation_id, nation_name, nation_code 
FROM nations 
LIMIT 10;

SELECT AVG((julianday('now') - julianday(date_of_birth)) / 365) AS average_age
FROM crews
WHERE crew_id IN (
    SELECT crew_id 
    FROM crew_assignments
);

SELECT boat_name
FROM boats
WHERE boat_id = 1;

SELECT COUNT(DISTINCT b.boat_id)
FROM boats b
WHERE CAST(b.weight_capacity AS REAL) < 500 AND CAST(b.boat_length AS REAL) < 10;

SELECT * 
FROM boats 
ORDER BY boat_name;

SELECT event_id, boat_id, nation_id
FROM results
ORDER BY event_id DESC;

external_knowledge:
- 'Perform poorly' in this context means finishing in positions worse than 5th; 
- 'Bottom half' of the race indicates positions generally below the 7th place;
- 'Rowers' specifically refers to crew members with the role 'Rower'.

